#include <iostream>
#include <vector>
using namespace std;

void heapifyUp(int& root, int child, int n, vector<int>& heap) {
  if (root == -1) return;
  if (heap[root] > heap[child]) {
    heap[root] = heap[child];
    root = child;
    heapifyUp(root, child, n, heap);
  }
}

void insert(int root, int val, int& res, vector<int>& heap) {
  int child = root * 2 + 1;
  while (child < heap.size()) {
    if (heap[child] >= val) {
      heap[root] = val;
      return;
    }
    heap[root] = heap[child];
    root = child;
    child = root * 2 + 1;
  }
  heap[root] = val;
  res = root;
}

int main() {
  vector<int> heap = {1, 2, 3, 4, 5};
  int res = 0;
  insert(0, 6, res, heap);
  print(heap);
  return 0;
}
